mapper.select:
select a.id, a.student_id as studentId, stu.name as studentName, 
a.attendance_date as attendanceDate, a.status, a.reason
from attendance a left join student stu on a.student_id = stu.id where a.id = #{id}

select a.id, a.student_id as studentId, stu.name as studentName, 
a.attendance_date as attendanceDate, a.status, a.reason
from attendance a left join student stu on a.student_id = stu.id


        and stu.name like concat('%', #{studentName}, '%')


        and a.status = #{status}


        and a.attendance_date = #{attendanceDate}
